int tlOpticVectorV14Chunk::sortPriority = -1;

tlOpticVectorV14Chunk::tlOpticVectorV14Chunk()
{
    Init();
}

tlOpticVectorV14Chunk::tlOpticVectorV14Chunk(const tlOpticVectorV14Chunk& ch)
{
    Init();
    *this = ch;
}

tlOpticVectorV14Chunk::~tlOpticVectorV14Chunk()
{

}

tlOpticVectorV14Chunk::tlOpticVectorV14Chunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::OpticEffect::VECTOR_V14);
    ident = Pure3D::OpticEffect::VECTOR_V14;

    tlFile* f = ch->GetFile();

    x = f->GetFloat();
    y = f->GetFloat();
    z = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::OpticEffect::VECTOR_V14);
    }
}

void
tlOpticVectorV14Chunk::Init()
{
    ident = Pure3D::OpticEffect::VECTOR_V14;
    x = 0.0f;
    y = 0.0f;
    z = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::OpticEffect::VECTOR_V14);
    }
}

long 
tlOpticVectorV14Chunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += sizeof( x );
    s += sizeof( y );
    s += sizeof( z );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlOpticVectorV14Chunk&
tlOpticVectorV14Chunk::operator=(const tlOpticVectorV14Chunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    x = a.x;
    y = a.y;
    z = a.z;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlOpticVectorV14Chunk::operator==(const tlDataChunk& a)
{

    const tlOpticVectorV14Chunk* aptr = dynamic_cast<const tlOpticVectorV14Chunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(!(x == aptr->x))
    {
        return false;
    }
    if(!(y == aptr->y))
    {
        return false;
    }
    if(!(z == aptr->z))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

