void
tlOpticVectorV14Chunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutFloat(x);
        f->PutFloat(y);
        f->PutFloat(z);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

