tlCoronaV14Chunk::tlCoronaV14Chunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::OpticEffect::CORONA_V14);
    ident = Pure3D::OpticEffect::CORONA_V14;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    f->GetPString(buf);
    shader = strnew(buf);
    colour = f->GetLong();
    textureframerate = f->GetLong();
    numtextureframes = f->GetLong();
    width = f->GetFloat();
    height = f->GetFloat();
    sourceradius = f->GetFloat();
    fallofftime = f->GetFloat();
    distancecutoff = f->GetFloat();
    perspectivescale = f->GetLong();
    framerate = f->GetFloat();
    billboardmode = f->GetLong();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::OpticEffect::CORONA_V14);
    }
}

