// tlLensFlareParentV14Chunk

int tlLensFlareParentV14Chunk::sortPriority = -1;

tlLensFlareParentV14Chunk::tlLensFlareParentV14Chunk()
{
    Init();
}

tlLensFlareParentV14Chunk::tlLensFlareParentV14Chunk(const tlLensFlareParentV14Chunk& ch)
{
    Init();
    *this = ch;
}

tlLensFlareParentV14Chunk::~tlLensFlareParentV14Chunk()
{

    if(name != NULL){
        strdelete(name);
    }
}

tlLensFlareParentV14Chunk::tlLensFlareParentV14Chunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::OpticEffect::LENS_FLARE_PARENT_V14);
    ident = Pure3D::OpticEffect::LENS_FLARE_PARENT_V14;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    name = strnew(buf);
    version = f->GetLong();
    numflares = f->GetLong();
    sourceradius = f->GetFloat();
    fallofftime = f->GetFloat();
    distancecutoff = f->GetFloat();
    framerate = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::OpticEffect::LENS_FLARE_PARENT_V14);
    }
}

void
tlLensFlareParentV14Chunk::Init()
{
    ident = Pure3D::OpticEffect::LENS_FLARE_PARENT_V14;
    name = NULL;
    version = 0;
    numflares = 0;
    sourceradius = 0.0f;
    fallofftime = 0.0f;
    distancecutoff = 0.0f;
    framerate = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::OpticEffect::LENS_FLARE_PARENT_V14);
    }
}

long 
tlLensFlareParentV14Chunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( name );
    s += sizeof( version );
    s += sizeof( numflares );
    s += sizeof( sourceradius );
    s += sizeof( fallofftime );
    s += sizeof( distancecutoff );
    s += sizeof( framerate );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlLensFlareParentV14Chunk&
tlLensFlareParentV14Chunk::operator=(const tlLensFlareParentV14Chunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    name = strnew(a.name);
    version = a.version;
    numflares = a.numflares;
    sourceradius = a.sourceradius;
    fallofftime = a.fallofftime;
    distancecutoff = a.distancecutoff;
    framerate = a.framerate;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlLensFlareParentV14Chunk::operator==(const tlDataChunk& a)
{

    const tlLensFlareParentV14Chunk* aptr = dynamic_cast<const tlLensFlareParentV14Chunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(name, aptr->name) != 0)
    {
        return false;
    }
    if(!(version == aptr->version))
    {
        return false;
    }
    if(!(numflares == aptr->numflares))
    {
        return false;
    }
    if(!(sourceradius == aptr->sourceradius))
    {
        return false;
    }
    if(!(fallofftime == aptr->fallofftime))
    {
        return false;
    }
    if(!(distancecutoff == aptr->distancecutoff))
    {
        return false;
    }
    if(!(framerate == aptr->framerate))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

