tlDataChunk*
tlLensFlareParentV14Chunk::LoadSubChunk(tlFile* f)
{
    tlDataChunk *dch;
    tlReadChunk16  ch(f);
    ch.ReadNext();
    unsigned int id = ch.GetID();
 
    switch(id)
    {
    case Pure3D::OpticEffect::LENS_FLARE_V14:
        dch = new tlLensFlareV14Chunk(&ch);
        break;
    case Pure3D::OpticEffect::VECTOR_V14:
        dch = new tlOpticVectorV14Chunk(&ch);
        break;
    default:
        dch = new tlDataChunk(id);
        int size = ch.GetDataSize();
        char* buf = new char[size];
        f->GetBytes(buf, size);
        dch->SetData(buf, size);
        delete buf;
    }
    ch.Skip();
    return dch;
}

