int tlLensFlareV14Chunk::sortPriority = -1;

tlLensFlareV14Chunk::tlLensFlareV14Chunk()
{
    Init();
}

tlLensFlareV14Chunk::tlLensFlareV14Chunk(const tlLensFlareV14Chunk& ch)
{
    Init();
    *this = ch;
}

tlLensFlareV14Chunk::~tlLensFlareV14Chunk()
{

    if(shader != NULL){
        strdelete(shader);
    }
}

tlLensFlareV14Chunk::tlLensFlareV14Chunk(tlReadChunk16* ch)
{
    assert(ch->GetID() == Pure3D::OpticEffect::LENS_FLARE_V14);
    ident = Pure3D::OpticEffect::LENS_FLARE_V14;

    tlFile* f = ch->GetFile();
    char buf[P3DMAXNAME];

    f->GetPString(buf);
    shader = strnew(buf);
    colour = f->GetLong();
    distance = f->GetFloat();
    width = f->GetFloat();
    height = f->GetFloat();
    while (!ch->EndOfChunk())
    {
        AppendSubChunk(LoadSubChunk(f));
    }
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::OpticEffect::LENS_FLARE_V14);
    }
}

void
tlLensFlareV14Chunk::Init()
{
    ident = Pure3D::OpticEffect::LENS_FLARE_V14;
    shader = NULL;
    colour = 0;
    distance = 0.0f;
    width = 0.0f;
    height = 0.0f;
               
    if(sortPriority == -1)
    {
        sortPriority = FindPriority(Pure3D::OpticEffect::LENS_FLARE_V14);
    }
}

long 
tlLensFlareV14Chunk::Size( )
{

    long s = 2*sizeof( long );

    int i;

    s += strlen( shader );
    s += sizeof( colour );
    s += sizeof( distance );
    s += sizeof( width );
    s += sizeof( height );
    for( i=0; i < SubChunkCount( ); i++){
        s += GetSubChunk(i)->Size();
    }

    return s;
}

tlLensFlareV14Chunk&
tlLensFlareV14Chunk::operator=(const tlLensFlareV14Chunk& a)
{

    if(ident != a.ident)
    {
        assert(ident != a.ident);
        return *this;
    }

    shader = strnew(a.shader);
    colour = a.colour;
    distance = a.distance;
    width = a.width;
    height = a.height;

    int subch;

    for(subch = 0; subch < subcount; subch++)
    {
        RemoveSubChunk(subch);
    }

    for(subch = 0; subch < a.subcount; subch++)
    {
        AppendSubChunk(a.GetSubChunk(subch)->Copy());
    }
    
    return *this;
}

bool
tlLensFlareV14Chunk::operator==(const tlDataChunk& a)
{

    const tlLensFlareV14Chunk* aptr = dynamic_cast<const tlLensFlareV14Chunk*>(&a);

    if(aptr == NULL)
    {
        return false;
    }

    if(ident != aptr->ident)
    {
        return false;
    }


    if(strcmp(shader, aptr->shader) != 0)
    {
        return false;
    }
    if(!(colour == aptr->colour))
    {
        return false;
    }
    if(!(distance == aptr->distance))
    {
        return false;
    }
    if(!(width == aptr->width))
    {
        return false;
    }
    if(!(height == aptr->height))
    {
        return false;
    }

    // check the subchunks
    if(subcount != aptr->subcount)
    {
        return false;
    }

    for(int subch = 0; subch < subcount; subch++)
    {
        if(!((*GetSubChunk(subch)) == (*aptr->GetSubChunk(subch))))
        {
            return false;
        }
    }
    return true;
}

bool
tlLensFlareV14Chunk::NameCompare(const tlDataChunk& a)
{

    // This chunk has no name, so we must compare the bits
    return operator==(a);
}


tlDataChunk*
tlLensFlareV14Chunk::Create(tlReadChunk16* ch)
{
    tlDataChunk* dtCh = new tlLensFlareV14Chunk(ch);
    return dtCh;
}

void
tlLensFlareV14Chunk::Write(tlFile* f)
{
    tlWriteChunk16 ch(f, ident);

        f->PutPString(shader);
        f->PutLong(colour);
        f->PutFloat(distance);
        f->PutFloat(width);
        f->PutFloat(height);

    ch.ContentFinish();
    for(int subch = 0; subch < subcount; subch++)
    {
        GetSubChunk(subch)->Write(f);
    }
}

void
tlLensFlareV14Chunk::Print(int indent, unsigned int printdepth, unsigned int typemask)
{

    if ( printdepth == 0 )
    {
        return;
    }

    printf("%*stlLensFlareV14Chunk (%4x)\n",indent,"",(int) ident);
    printf("%*s  Shader   = \"%s\"\n",indent,"",shader);
    printf("%*s  Colour   = %08lx\n",indent,"",colour);
    printf("%*s  Distance = %f\n",indent,"",distance);
    printf("%*s  Width    = %f\n",indent,"",width);
    printf("%*s  Height   = %f\n",indent,"",height);

    if(subcount)
    {
        printf("%*s  SubChunks (%d):\n",indent,"",subcount);
        for(int subch = 0; subch < subcount; subch++)
        {
            GetSubChunk(subch)->Print(indent+4, printdepth-1, typemask);
        }
    }
}

void
tlLensFlareV14Chunk::PrintFormatted(int indent)
{
    printf("%*schunk 0x%04x  \n",indent,"",(int) ident);
    printf("%*s  pstring \"%s\" # Shader  \n",indent,"",shader);
    printf("%*s  int   0x%08lx # Colour  \n",indent,"",colour);
    printf("%*s  float %12f # Distance\n",indent,"",distance);
    printf("%*s  float %12f # Width   \n",indent,"",width);
    printf("%*s  float %12f # Height  \n",indent,"",height);
    if(subcount)
    {
        for(int i=0;i<subcount;i++)
        {
            GetSubChunk(i)->PrintFormatted(indent+2);
        }
    }
    printf("%*sendchunk\n",indent,"");
}

